// ─── Sound ─────────────────────────────────────────────────
function playBeep(type) {
  try {
    var src = type === "call" ? SND_CALL : SND_ORDER;
    var audio = new Audio(src);
    audio.volume = 1.0;
    audio.play();
  } catch(e) {}
}

